from datetime import datetime

from pydantic import Field

from maascommon.enums.service import ServiceName, ServiceStatusEnum
from maasservicelayer.models.base import ResourceBuilder, UNSET, Unset


class ServiceStatusBuilder(ResourceBuilder):
    """Autogenerated from utilities/generate_builders.py.

    You can still add your custom methods here, they won't be overwritten by
    the generated code.
    """

    created: datetime | Unset = Field(default=UNSET)
    name: ServiceName | Unset = Field(default=UNSET)
    node_id: int | Unset = Field(default=UNSET)
    status: ServiceStatusEnum | Unset = Field(default=UNSET)
    status_info: str | Unset = Field(default=UNSET)
    updated: datetime | Unset = Field(default=UNSET)
